public class Solution {
    public String getSmallestString(int n, int k) {
        char[] result = new char[n];
        k -= n;
        for (int i = n - 1; i >= 0; --i) {
            int value = Math.min(k, 25);
            result[i] = (char) ('a' + value);
            k -= value;
            if (k == 0) break;
        }
        return new String(result);
    }
}
```

